#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int isInteger(char *str);

void read_file(char* filename,
               float* input,
               int data_rows,
               int data_cols,
               int major);

int kernel_gpu_opencl_wrapper(int xmax,
                              int workload,
                              float*** y,
                              float** x,
                              float** params,
                              float* com);

int device_id_inuse = 0;
int platform_id_inuse = 0;

int main(int argc, char *argv[]) {

    int cur_arg;
    int xmax;
    int workload = 1;
    char *data_dir;

    if (3 < argc) {
        for (cur_arg = 1; argc > cur_arg; cur_arg++) {

            if (strcmp(argv[cur_arg], "-time") == 0) {

                if (cur_arg + 1 <= argc) {

                    if (1 == isInteger(argv[cur_arg + 1])) {
                        xmax = atoi(argv[cur_arg + 1]);
                        if (0 > xmax) {
                            printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
                            return 0;
                        }
                        cur_arg += 1;
                    } else {
                        printf("RROR: Value to -time argument in not a number\n");
                        return 0;
                    }
                } else {
                    printf("ERROR: Missing value to -time argument\n");
                    return 0;
                }
            } else if (strcmp(argv[cur_arg], "-p") == 0) {
                if (cur_arg + 1 <= argc)
                    if (1 == isInteger(argv[cur_arg + 1])) {
                        platform_id_inuse = atoi(argv[cur_arg + 1]);
                        cur_arg += 1;
                    }
            } else if (strcmp(argv[cur_arg], "-d") == 0) {
                if (cur_arg + 1 <= argc)
                    if (1 == isInteger(argv[cur_arg + 1])) {
                        device_id_inuse = atoi(argv[cur_arg + 1]);
                        cur_arg += 1;
                    }
            } else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (cur_arg + 1 <= argc) {
                    data_dir = argv[cur_arg + 1];
                    cur_arg++;
                }
            } else {
                printf("ERROR: Unknown argument\n");
                return 0;
            }
        }

    } else {
        printf("Provide time argument, example: -time 100");
        return 0;
    }

    if (1 == workload) {

        int i, j;

        long long memory;
        memory = workload * (xmax + 1) * 91 * 4;
        if (1000000000 < memory) {
            printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
            return 0;
        }

        float ***y;
        y = (float ***)malloc(workload * sizeof(float **));
        for (i = 0; workload > i; i++) {
            y[i] = (float **)malloc((1 + xmax) * sizeof(float *));
            for (j = 0; (1 + xmax) > j; j++) {
                y[i][j] = (float *)malloc(91 * sizeof(float));
            }
        }

        float **x;
        x = (float **)malloc(workload * sizeof(float *));
        for (i = 0; workload > i; i++) {
            x[i] = (float *)malloc((1 + xmax) * sizeof(float));
        }

        float **params;
        params = (float **)malloc(workload * sizeof(float *));
        for (i = 0; workload > i; i++) {
            params[i] = (float *)malloc(18 * sizeof(float));
        }

        float *com;
        com = (float *)malloc(3 * sizeof(float));

        char y_file[100];
        sprintf(y_file, "%s/%s", data_dir, "y.txt");
        for (i = 0; workload > i; i++) {
            read_file(y_file,
                      y[i][0],
                      91,
                      1,
                      0);
        }

        char params_file[100];
        sprintf(params_file, "%s/%s", data_dir, "params.txt");
        for (i = 0; workload > i; i++) {
            read_file(params_file,
                      params[i],
                      18,
                      1,
                      0);
        }

        kernel_gpu_opencl_wrapper(xmax,
                                  workload,

                                  y,
                                  x,
                                  params,
                                  com);

        FILE *pFile;
        pFile = fopen("output.txt", "w");
        if (pFile == NULL) {
            fputs("fopen example", pFile);
            return -1;
        }

        int k;
        for (i = 0; workload > i; i++) {
            fprintf(pFile, "WORKLOAD %d:\n", i);
            for (j = 0; (xmax + 1) > j; j++) {
                fprintf(pFile, "\tTIME %d:\n", j);
                for (k = 0; k < 91; k++) {
                    fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
                }
            }
        }

        fclose(pFile);

        for (i = 0; workload > i; i++) {
            for (j = 0; (1 + xmax) > j; j++) {
                free(y[i][j]);
            }
            free(y[i]);
        }
        free(y);

        for (i = 0; workload > i; i++) {
            free(x[i]);
        }
        free(x);

        for (i = 0; workload > i; i++) {
            free(params[i]);
        }
        free(params);

        free(com);
    }

    return 0;
}
